{"content":"package ru.samtakoy.quotes.mapper

import ru.samtakoy.quotes.dto.MarketDto
import ru.samtakoy.quotes.domain.model.Market

object MarketMapper {
  fun toDomain(dto: MarketDto): Market {
    if (dto.title == null) throw IllegalArgumentException("Title cannot be null")
    return Market(
      id = dto.id,
      title = dto.title
    )
  }
}"}

