{"path":"modules/features/feature-quotes/src/commonTest/kotlin/ru/samtakoy/quotes/mapper/MarketMapperTest.kt","content":"package ru.samtakoy.quotes.mapper

import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFailsWith
import ru.samtakoy.quotes.dto.MarketDto
import ru.samtakoy.quotes.domain.model.Market
import ru.samtakoy.quotes.mapper.MarketMapper

class MarketMapperTest {
  @Test
  fun toDomain_validFields_mapsCorrectly() {
    val dto = MarketDto(id = "1", title = "Test Market")
    val domain = MarketMapper.toDomain(dto)
    assertEquals("1", domain.id)
    assertEquals("Test Market", domain.title)
  }

  @Test
  fun toDomain_nullTitle_throwsIllegalArgumentException() {
    val dto = MarketDto(id = "1", title = null)
    assertFailsWith<IllegalArgumentException> {
      MarketMapper.toDomain(dto)
    }
  }
}"}
